UPDATE pricingConfig SET descriptionTemplate = 'Cocina integral con muebles inferiores y superiores en melamina estándar. Incluye mesón en sinterizado. Herrajes básicos de buena calidad. Acabado limpio y funcional.' WHERE code = 'COCINA_ML_L';

UPDATE pricingConfig SET descriptionTemplate = 'Cocina premium con muebles inferiores y superiores en melamina de alta calidad. Incluye mesón en sinterizado. Herrajes con cierre lento y LED integrado en algunos módulos. Acabado superior con detalles mejorados.' WHERE code = 'COCINA_ML_U';

UPDATE pricingConfig SET descriptionTemplate = 'Cocina deluxe con muebles inferiores y superiores en melamina premium. Incluye mesón en sinterizado. Herrajes importados con cierre lento suave. LED integrado en todos los módulos. Acabados especiales y detalles de lujo. Máxima durabilidad y estética.' WHERE code = 'COCINA_ML_LINEAL';

